import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { isLocalCaptureDisabled } from "./index.js";
describe("isLocalCaptureDisabled", () => {
    let tempHome;
    const originalHome = process.env.HOME;
    const originalEnv = process.env.BITFAB_CAPTURE_SESSIONS;
    beforeEach(() => {
        tempHome = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-optout-"));
        process.env.HOME = tempHome;
        delete process.env.BITFAB_CAPTURE_SESSIONS;
    });
    afterEach(() => {
        process.env.HOME = originalHome;
        if (originalEnv === undefined) {
            delete process.env.BITFAB_CAPTURE_SESSIONS;
        }
        else {
            process.env.BITFAB_CAPTURE_SESSIONS = originalEnv;
        }
        fs.rmSync(tempHome, { recursive: true, force: true });
    });
    it("defaults to disabled when no config and no env var", () => {
        expect(isLocalCaptureDisabled()).toBe(true);
    });
    it("env var BITFAB_CAPTURE_SESSIONS=1 enables", () => {
        process.env.BITFAB_CAPTURE_SESSIONS = "1";
        expect(isLocalCaptureDisabled()).toBe(false);
    });
    it("env var BITFAB_CAPTURE_SESSIONS=true enables", () => {
        process.env.BITFAB_CAPTURE_SESSIONS = "true";
        expect(isLocalCaptureDisabled()).toBe(false);
    });
    it("env var BITFAB_CAPTURE_SESSIONS=0 disables", () => {
        process.env.BITFAB_CAPTURE_SESSIONS = "0";
        expect(isLocalCaptureDisabled()).toBe(true);
    });
    it("env var BITFAB_CAPTURE_SESSIONS=false disables", () => {
        process.env.BITFAB_CAPTURE_SESSIONS = "false";
        expect(isLocalCaptureDisabled()).toBe(true);
    });
    it("env var overrides config-file enable", () => {
        fs.mkdirSync(path.join(tempHome, ".config", "bitfab"), { recursive: true });
        fs.writeFileSync(path.join(tempHome, ".config", "bitfab", "config.json"), JSON.stringify({ sessionLogConsent: true }));
        process.env.BITFAB_CAPTURE_SESSIONS = "0";
        expect(isLocalCaptureDisabled()).toBe(true);
    });
    it("config file sessionLogConsent=true enables", () => {
        fs.mkdirSync(path.join(tempHome, ".config", "bitfab"), { recursive: true });
        fs.writeFileSync(path.join(tempHome, ".config", "bitfab", "config.json"), JSON.stringify({ sessionLogConsent: true }));
        expect(isLocalCaptureDisabled()).toBe(false);
    });
    it("config file sessionLogConsent=false disables", () => {
        fs.mkdirSync(path.join(tempHome, ".config", "bitfab"), { recursive: true });
        fs.writeFileSync(path.join(tempHome, ".config", "bitfab", "config.json"), JSON.stringify({ sessionLogConsent: false }));
        expect(isLocalCaptureDisabled()).toBe(true);
    });
    it("malformed config file falls back to disabled", () => {
        fs.mkdirSync(path.join(tempHome, ".config", "bitfab"), { recursive: true });
        fs.writeFileSync(path.join(tempHome, ".config", "bitfab", "config.json"), "not json");
        expect(isLocalCaptureDisabled()).toBe(true);
    });
});
